// @vitest-environment node
/**
 * Config-hygiene regression tests for the repo's ESLint flat config.
 *
 * Background — final-review finding "Code Quality (medium): Duplicate ESLint
 * config imports non-existent dependency and is shadowed by eslint.config.mjs":
 *
 *   Two ESLint flat-config files briefly coexisted at the repo root:
 *   `eslint.config.js` and `eslint.config.mjs`. The `.js` file imported
 *   `@typescript-eslint/parser`, a package that is NOT a project dependency —
 *   it appears in neither `package.json` nor `node_modules`. So whichever of
 *   the two configs ESLint happened to resolve, the `.js` one was either dead
 *   (shadowed by `.mjs`) or actively broken (crashing on import of a missing
 *   package). The `.mjs` config is the self-contained, documented survivor: it
 *   defines a lenient passthrough parser inline, imports nothing from npm, and
 *   explains in a header comment that real linting is the job of `oxlint`.
 *
 *   The fix was to DELETE `eslint.config.js`, leaving exactly one config. These
 *   tests pin that end state so the broken duplicate cannot silently return:
 *
 *     1. `eslint.config.js` must not exist on disk;
 *     2. exactly one `eslint.config.*` file may exist at the repo root, and it
 *        must be `eslint.config.mjs`;
 *     3. no remaining ESLint config may import `@typescript-eslint/parser`;
 *     4. `@typescript-eslint/parser` must stay out of package.json deps;
 *     5. the surviving `eslint.config.mjs` must be loadable and zero-dependency.
 *
 * These tests inspect the filesystem directly (no DOM), so the environment is
 * pinned to `node` — mirroring `readme.test.ts` / `index.html.test.ts` /
 * `app.css.test.ts`.
 */
import { describe, it, expect } from 'vitest';
import { existsSync, readdirSync, readFileSync } from 'node:fs';
import { resolve, dirname, basename } from 'node:path';
import { fileURLToPath, pathToFileURL } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = resolve(__dirname, '..');

const ESLINT_JS = resolve(REPO_ROOT, 'eslint.config.js');
const ESLINT_MJS = resolve(REPO_ROOT, 'eslint.config.mjs');
const PACKAGE_JSON = resolve(REPO_ROOT, 'package.json');
const NODE_MODULES = resolve(REPO_ROOT, 'node_modules');

/**
 * The names (basename) of every `eslint.config.*` file directly in the repo
 * root, sorted. Used to assert there is exactly one and to scan each for the
 * forbidden import.
 */
function eslintConfigFiles(): string[] {
  return readdirSync(REPO_ROOT)
    .filter((name) => /^eslint\.config\./.test(name))
    .map((name) => basename(name))
    .sort();
}

/* ===========================================================================
 * Contract 1 — exactly one, well-formed ESLint config file remains
 * ========================================================================= */
describe('ESLint flat config — single config file remains', () => {
  it('the broken duplicate `eslint.config.js` has been deleted', () => {
    // eslint.config.js imported @typescript-eslint/parser (not installed), so it
    // would crash ESLint if ever loaded. It must not exist on disk.
    expect(existsSync(ESLINT_JS), 'eslint.config.js must be removed').toBe(false);
  });

  it('exactly one `eslint.config.*` file exists at the repo root', () => {
    const files = eslintConfigFiles();
    expect(
      files,
      `expected exactly one eslint config, found ${files.length}: ${files.join(', ')}`,
    ).toEqual(['eslint.config.mjs']);
  });

  it('the surviving config is `eslint.config.mjs`', () => {
    expect(existsSync(ESLINT_MJS), 'eslint.config.mjs must exist').toBe(true);
  });
});

/* ===========================================================================
 * Contract 2 — no remaining config depends on the un-installed parser
 * ========================================================================= */
describe('ESLint flat config — no dependency on @typescript-eslint/parser', () => {
  it('no remaining eslint config imports @typescript-eslint/parser', () => {
    // Guards against the exact bug: a config that imports a package not present
    // in node_modules. With only eslint.config.mjs surviving (which imports
    // nothing), this must hold for every config file present.
    const files = eslintConfigFiles();
    expect(files.length, 'at least one eslint config must exist').toBeGreaterThan(0);
    for (const name of files) {
      const text = readFileSync(resolve(REPO_ROOT, name), 'utf8');
      expect(
        text,
        `${name} must not import @typescript-eslint/parser (it is not a project dependency)`,
      ).not.toMatch(/@typescript-eslint\/parser/);
    }
  });

  it('`@typescript-eslint/parser` is not declared anywhere in package.json', () => {
    // Pin the existing-correct state so a future change does not quietly
    // re-add the parser as a dependency to "fix" a config that imports it.
    const pkg = JSON.parse(readFileSync(PACKAGE_JSON, 'utf8'));
    const allDeps: Record<string, unknown> = {
      ...(pkg.dependencies ?? {}),
      ...(pkg.devDependencies ?? {}),
      ...(pkg.peerDependencies ?? {}),
      ...(pkg.optionalDependencies ?? {}),
    };
    expect(allDeps).not.toHaveProperty('@typescript-eslint/parser');
  });

  it('`@typescript-eslint/parser` is not installed in node_modules', () => {
    // A config importing this package would only ever have worked if it were
    // installed. It is not, and must not be (ESLint itself is not a dependency;
    // linting is done by oxlint).
    expect(
      existsSync(resolve(NODE_MODULES, '@typescript-eslint/parser')),
      '@typescript-eslint/parser must not be present in node_modules',
    ).toBe(false);
  });
});

/* ===========================================================================
 * Contract 3 — the surviving eslint.config.mjs is loadable & self-contained
 * ========================================================================= */
describe('ESLint flat config — surviving eslint.config.mjs is valid', () => {
  it('imports no bare npm packages (stays zero-dependency)', () => {
    // The .mjs config is deliberately self-contained: it defines its parser
    // inline. Asserting it has NO bare-specifier (`from 'pkg'`) imports makes
    // sure it can never regress into importing a missing package the way the
    // deleted .js config did. Relative `./` / `../` imports would still be fine.
    const text = readFileSync(ESLINT_MJS, 'utf8');
    expect(text, 'eslint.config.mjs must not contain bare-package imports').not.toMatch(
      /^\s*import\b[\s\S]*?\bfrom\s*['"][^./]/m,
    );
  });

  it('exports a flat config array (default export is a non-empty array)', async () => {
    // Actually import the module to prove it loads without throwing (the thing
    // the deleted .js config could NOT do, because of its missing import) and
    // that it exports the expected ESLint flat-config shape.
    const mod = (await import(pathToFileURL(ESLINT_MJS).href)) as { default: unknown };
    expect(Array.isArray(mod.default), 'default export must be an array').toBe(true);
    expect(
      (mod.default as unknown[]).length,
      'flat config array must contain at least one config object',
    ).toBeGreaterThan(0);
  });

  it('provides a `languageOptions.parser` so ESLint need not parse TS natively', () => {
    // The lenient passthrough parser is the whole point of the surviving config:
    // it lets ESLint "match" .ts/.tsx files without the typescript-eslint
    // parser. Confirm the config text declares a parser.
    const text = readFileSync(ESLINT_MJS, 'utf8');
    expect(text, 'config must set a languageOptions.parser').toMatch(/parser\s*:/);
  });
});

